import React from "react";
import { Link, useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  const user = JSON.parse(localStorage.getItem("user"));
  const role = user?.role;

  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/");
  };

  return (
    <div className="bg-indigo-600 text-white px-6 py-4 flex justify-between items-center shadow-md">

      {/* Left - Logo */}
      <h1 className="text-xl font-bold">Roxiler</h1>

      {/* Right - Menu */}
      <div className="flex items-center gap-6 text-sm font-medium">

        {/* ADMIN */}
        {role === "admin" && (
          <>
            <Link to="/admin-dashboard" className="hover:underline">Home</Link>
            <Link to="/users" className="hover:underline">Users</Link>
            <Link to="/stores" className="hover:underline">Stores</Link>
          </>
        )}

        {/* USER */}
        {role === "user" && (
          <>
            <Link to="/dashboard" className="hover:underline">Stores</Link>
          </>
        )}

        {/* STORE OWNER */}
        {role === "store_owner" && (
          <>
            <Link to="/store-dashboard" className="hover:underline">Home</Link>
            <Link to="/your-stores" className="hover:underline">Your Stores</Link>
          </>
        )}

        {/* COMMON */}
        {(role === "admin" || role === "user") && (
          <button
            onClick={() => alert("Open update password modal")}
            className="hover:underline"
          >
            Update Password
          </button>
        )}

        <button
          onClick={handleLogout}
          className="bg-red-500 px-3 py-1 rounded hover:bg-red-600"
        >
          Logout
        </button>

      </div>
    </div>
  );
}

export default Navbar;
